  // ── Logger ─────────────────────────────────────────────────────────────────
  // Cria logger com prefixo colorido
  function agMakeLog(prefix, color) {
    const s  = 'color:' + color + ';font-weight:bold;';
    const sw = 'color:#f59e0b;font-weight:bold;';
    const se = 'color:#f87171;font-weight:bold;';
    const sd = 'color:#64748b;font-weight:bold;';
    function fmt(style, args) {
      const parts = [prefix + ' ' + (typeof args[0] === 'string' ? args[0] : ''), style];
      const rest = typeof args[0] === 'string' ? args.slice(1) : args;
      return ['%c' + parts[0], parts[1], ...rest];
    }
    return {
      info:  (...a) => { agPersistLog('INFO',  prefix, a); console.info( ...fmt(s,  a)); },
      warn:  (...a) => { agPersistLog('WARN',  prefix, a); console.warn( ...fmt(sw, a)); },
      error: (...a) => { agPersistLog('ERROR', prefix, a); console.error(...fmt(se, a)); },
      debug: (...a) => { agPersistLog('DEBUG', prefix, a); console.debug(...fmt(sd, a)); },
      group: (label) => console.group('%c' + prefix + ' ' + label, s),
      groupEnd: () => console.groupEnd(),
    };
  }
  const AG_LOG        = agMakeLog('[Farm]',     '#6ee7a0');
  const AG_LOG_WD     = agMakeLog('[Watchdog]', '#f59e0b');
  const AG_LOG_SELL   = agMakeLog('[AutoSell]', '#c084fc');
  const AG_LOG_SRV    = agMakeLog('[Server]',   '#38bdf8');
