  var _agLastServerClick = 0;
  function agAutoJoinServer() {
    var now = Date.now();
    if (now - _agLastServerClick < 8000) return; // throttle 8s entre tentativas
    _agLastServerClick = now;

    var targetServer = agOptCfg.server || '';
    AG_LOG.info('[AutoJoin] Tentando entrar no servidor: ' + (targetServer || 'qualquer'));

    // 1. Se há servidor configurado, buscar pelo nome
    if (targetServer) {
      var cards = Array.from(document.querySelectorAll('.kintara-server-card, .kintara-server-list__item'));
      for (var i = 0; i < cards.length; i++) {
        var card = cards[i];
        var txt = card.textContent || '';
        if (txt.toLowerCase().includes(targetServer.toLowerCase())) {
          var btn = card.querySelector('button:not(:disabled)') || card;
          if (btn && typeof btn.click === 'function') {
            AG_LOG.info('[AutoJoin] Clicando em servidor: ' + txt.trim().slice(0,40));
            btn.click();
            return;
          }
        }
      }
    }

    // 2. Clicar no primeiro botão de servidor disponível (não desabilitado, não FULL)
    var allBtns = Array.from(document.querySelectorAll('.kintara-server-select-btn'));
    var eligible = allBtns.filter(function(b) {
      if (b.disabled) return false;
      var txt = (b.textContent || '').toUpperCase();
      if (txt.includes('FULL') && !txt.includes('QUEUE')) return false;
      return true;
    });
    if (eligible.length > 0) {
      AG_LOG.info('[AutoJoin] Clicando btn: ' + eligible[0].textContent.trim().slice(0,30));
      eligible[0].click();
      return;
    }

    // 3. Fallback: qualquer botão visível na lista de servidores
    var listBtns = Array.from(document.querySelectorAll(
      '.kintara-server-card button, .kintara-server-list button, [class*="server"] button'
    )).filter(function(b) { return !b.disabled; });
    if (listBtns.length > 0) {
      AG_LOG.info('[AutoJoin] Fallback: clicando primeiro btn disponível');
      listBtns[0].click();
    }
  }

