  /** Sem floor cache — floor não é mais usado no score */
  const agOptFloorCache = {}; // mantido para não quebrar referências no debug log
  function agOptFarmRefreshFloors() {} // no-op

  // ── Config do Farm Otimizado (lida/salva no localStorage) ─────────────────
  // Score = peso / log2(dist + 2)  — simples e previsível
  const AG_OPT_CFG_KEY = 'kintara_ag_opt_cfg';
  var agOptCfg = (function() {
    var def = {
      searchRange:     30,                              // raio máximo de busca — recursos além ignorados
      priority:        { coal:4, stone:3, metal:2, wood:1 }, // peso por tipo
      noise:           0.10,                            // ruído 0–0.5 (dispersa múltiplas contas)
      poolSize:        3,                               // top-N sorteados (1–5)
      harvestMs:       300,                             // cooldown entre coletas (ms) — reduzido
      bugThresholdMs:  10000,                           // ms sem ganhar item = tile bugado (10–20s)
      clusterBonus:    true,                            // +15% por tile extra no cluster
    };
    try {
      var raw = localStorage.getItem(AG_OPT_CFG_KEY);
      if (!raw) return def;
      var s = JSON.parse(raw);
      s.searchRange  = Number(s.searchRange)  || def.searchRange;
      s.noise        = typeof s.noise === 'number' ? Math.min(0.5, Math.max(0, s.noise)) : def.noise;
      s.poolSize     = Math.min(5, Math.max(1, Number(s.poolSize)  || def.poolSize));
      s.harvestMs      = Math.min(2000, Math.max(400, Number(s.harvestMs) || def.harvestMs));
      s.bugThresholdMs = Math.min(20000, Math.max(10000, Number(s.bugThresholdMs) || def.bugThresholdMs));
      s.priority       = Object.assign({}, def.priority, s.priority || {});
      s.clusterBonus   = s.clusterBonus !== false;
      return s;
    } catch(_) { return def; }
  })();

  function agOptSaveCfg() {
    try { localStorage.setItem(AG_OPT_CFG_KEY, JSON.stringify(agOptCfg)); } catch(_) {}
  }

  /**
   * Score do Farm Otimizado — simples e previsível:
   *   score = peso * clusterMul * noise / log2(dist + 2)
   *
   * - peso:       configurado pelo usuário por tipo (coal=4, stone=3, metal=2, wood=1)
   * - clusterMul: +15% por tile extra no cluster (se clusterBonus ativado)
   * - noise:      ±noise% para dispersar múltiplas contas no mesmo servidor
   * - dist:       distância Manhattan até o tile de abordagem
   *
   * Não há floor, não há ban list, não há priority range — score é determinístico
   * e proporcional apenas ao peso e à distância.
   */
  function agOptScore(type, dist, clusterSize) {
    var priority   = agOptCfg.priority[type] || 1;
    var clSize     = clusterSize || 1;
    var clusterMul = agOptCfg.clusterBonus ? (1 + (clSize - 1) * 0.15) : 1;
    var distPenalty = Math.log2(dist + 2);
    var noiseRange  = agOptCfg.noise || 0;
    var noise       = 1 - noiseRange + Math.random() * noiseRange * 2;
    return (priority * clusterMul / distPenalty) * noise;
  }

  function agStartRestoreMonitor() {
    if (agRestoreTriggered) return;
    agRestoreCheckTimer = setInterval(() => {
      if (!(Re != null)) return;
      clearInterval(agRestoreCheckTimer);
      agRestoreCheckTimer = null;
      agRestoreTriggered = true;
    agRestorePersistedBans();

      // Startup config (permanente) tem prioridade sobre estado salvo
      let cfg = {};
      try { const r = localStorage.getItem('kintara_ag_startup'); cfg = r ? JSON.parse(r) : {}; } catch (_) {}
      const saved = agLoadState();

      const targetMode = cfg.mode || saved?.mode || null;
      // Farm Otimizado persiste no agOptCfg (sem TTL) — restaura independente do mode
      const optWasActive = !!(saved?.optimizedFarm || agOptCfg.optimizedFarmActive);

      if (!targetMode) {
        // Sem mode salvo — só restaura Farm Otimizado se o mode atual já é 'all'
        if (optWasActive && agMode === 'all') {
          agOptimizedFarm = true;
          agOptUpdateIndicator();
          AG_OPT_LOG.warn('RESTAURADO após restart (sem mode salvo) — Farm Otimizado ativo');
        }
        return;
      }

      agMode = targetMode;

      // Atualiza UI via shadow root
      const _sh2 = document.getElementById('ag-panel-host')?.shadowRoot;
      const modeEl = _sh2?.getElementById('ag-mode');
      if (modeEl) modeEl.value = agMode;
      agRefreshHint();

      const shouldAutostart = !!(cfg.autostart || saved?.active);
      const shouldAutonav   = !!cfg.autonav;

      // Restaura Farm Otimizado — agOptCfg.optimizedFarmActive não tem TTL
      if (optWasActive && agMode === 'all') {
        agOptimizedFarm = true;
        agOptUpdateIndicator();
        agOptFarmRefreshFloors();
        AG_OPT_LOG.warn('RESTAURADO após restart — Farm Otimizado ativo');
      }

      // Aplica mapa de farm do startup config
      if (cfg.reacm) {
        agFarmRealm = cfg.reacm;
        const frEl = _sh2?.getElementById('ag-farm-realm');
        if (frEl) frEl.value = cfg.realm || '';
        agStartRealmCheck();
      }

      function doStart() {
        if (!shouldAutostart) return;
        setTimeout(() => {
          agStart();
          agSetStatus('Restaurado apos restart');
        }, 1000);
      }

      // Auto-navegar para o mapa certo
      if (shouldAutonav && h==='world') {
        const needsFish = agMode === 'fish' && !AG_FISHING_REALMS.has(h);
        if (needsFish) {
          agNavSetStatus('🔄 Indo para Pond…');
          agNavTo('pond');
          const wait = setInterval(() => {
            if (agNavTarget) return;
            clearInterval(wait);
            doStart();
          }, 500);
          return;
        }
      }

      doStart();
      // Auto-caça NUNCA é restaurada automaticamente — só via F7

    }, 500);
  }


  // ── Anti-stuck watchdog ────────────────────────────────────────────────────
  // Se os itens coletados não aumentarem em X minutos, faz reload
  const AG_WATCHDOG_DEFAULT_ATTEMPTS = 5; // tentativas a cada 60s
  let agWatchdogTimer  = null;
  let agWatchdogLastItems = 0;
  let agWatchdogLastAt    = 0;

  function agGetWatchdogAttempts() {
    try {
      const raw = localStorage.getItem('kintara_ag_watchdog_ms');
      if (raw === null) return AG_WATCHDOG_DEFAULT_ATTEMPTS; // nao configurado = usa padrao
      const v = Number(raw);
      if (v === 0) return 0; // desativado explicitamente
      return v > 0 ? v : AG_WATCHDOG_DEFAULT_ATTEMPTS;
    } catch(_) { return AG_WATCHDOG_DEFAULT_ATTEMPTS; }
  }

  // True only when player is fully in-game (not in queue/boot screen)
  function agHudVisible() {
    // Estratégia: verificar múltiplos indicadores de "em jogo" em ordem de confiabilidade
    try {
      // 1. kintara-hud-root — container raiz do HUD, sempre presente em jogo
      const hudRoot = document.getElementById('kintara-hud-root');
      if (hudRoot) {
        const r = hudRoot.getBoundingClientRect();
        if (r.width > 0 || hudRoot.children.length > 0) return true;
      }
      // 2. Qualquer botão do HUD (metal-btn) — fallback para versões anteriores
      const anyHudBtn = document.querySelector('.kintara-hud-metal-btn');
      if (anyHudBtn) {
        const r2 = anyHudBtn.getBoundingClientRect();
        if (r2.width > 0 && r2.height > 0) return true;
      }
      // 3. Canvas do Three.js renderer — sempre presente quando o jogo carregou
      const canvas = document.querySelector('canvas');
      if (canvas && canvas.width > 0 && canvas.height > 0) return true;
    } catch(_) {}
    return false;
  }

  /** Retorna true se tela de seleção/fila de servidor está visível */
  function agServerScreenVisible() {
    function isVisible(el) {
      if (!el) return false;
      const r = el.getBoundingClientRect();
      return r.width > 0 && r.height > 0;
    }
    try {
      // Tela de escolha de servidor — só se visível
      const sel = document.querySelector('.kintara-server-select-list');
      if (sel && isVisible(sel)) return true;
      // Cards de servidor visíveis
      const cards = document.querySelectorAll('.kintara-server-card');
      if (Array.from(cards).some(isVisible)) return true;
      // Botões de fila visíveis
      const qBtns = document.querySelectorAll('.kintara-server-select-btn');
      if (Array.from(qBtns).some(isVisible)) return true;
      // Botões com texto de fila — apenas se visíveis
      const allBtns = Array.from(document.querySelectorAll('button'));
      const hasQueueBtn = allBtns.some(function(b) {
        if (!isVisible(b)) return false;
        var t = (b.textContent || '').toLowerCase().trim();
        return t === 'leave queue' || t === 'pick a different server' ||
               t === 'leave a queue';
      });
      if (hasQueueBtn) return true;
      // Elemento visível com texto de fila (NOT body.textContent — muito abrangente)
      const queueEls = document.querySelectorAll('[class*="queue"],[id*="queue"],[class*="Queue"],[id*="Queue"]');
      if (Array.from(queueEls).some(isVisible)) return true;
    } catch(_) {}
    return false;
  }

  /** Retorna true se o m atual não permite farm (cave, shack, etc.) */
  function agGameStateBlocksFarm() {
    return h==='wild_ext_cave'; // Glade Cave — sem recursos coletáveis
  }

  function agIsInGame() {
    if (!agHudVisible()) return false;
    if (agServerScreenVisible()) return false;
    if (!(Re != null)) return false;
    if (agGameStateBlocksFarm()) return false;
    if (agMode === 'fish') {
      if (!AG_FISHING_REALMS.has(h)) return false;
    } else {
      if (!JY()) return false;
    }
    if (h === 'shack') return false;
    return true;
  }

  function agIsInGame2() {
    if (!agHudVisible()) return false;
    if (agServerScreenVisible()) return false;
    if (!(Re != null)) return false;
    if (agGameStateBlocksFarm()) return false;
    // Em modo pesca, verificar se o realm suporta pesca em vez de JY()
    if (agMode === 'fish') {
      if (!AG_FISHING_REALMS.has(h) && h !== 'shack') return false;
    } else {
      if (!JY() && h !== 'shack') return false;
    }
    return true;
  }

