  // Encontra um tile do portal para o realm destino (a partir do world)
  function agNavGetPortalTile(targetRealm) {
    // Usar try/catch em vez de typeof — mais robusto com imports ES module
    function fromSet(s) {
      try {
        if (!s || !s.size) return null;
        for (const k of s) {
          const [c,r] = k.split(',').map(Number);
          if (!isNaN(c) && !isNaN(r)) return {col:c, row:r};
        }
      } catch(_) {}
      return null;
    }
    try {
      if (targetRealm === 'pond') {
        return fromSet(h6);  // pondPortalWorldSet
      }
      if (targetRealm === 'eldergrove') {
        // Primeiro tenta via eldergrovePortalWorldSet (w6)
        const t = fromSet(w6);
        if (t) return t;
        // Fallback via ELDERGROVE_PORTAL_COLS + ROW
        try {
          const col = Array.isArray(NS) ? NS[0] : NS;
          if (col != null && zk != null) return {col, row: zk};
        } catch(_) {}
        return null;
      }
      if (targetRealm === 'wild' || targetRealm === 'wild_ext' || targetRealm === 'wild_exp') {
        // wildPortalWorldSet (VE)
        const t = fromSet(VE);
        if (t) return t;
        // Fallback via WILD_PORTAL_MID + ROW
        try { if (Ag != null && zk != null) return {col: Ag, row: zk}; } catch(_) {}
        return null;
      }
      if (targetRealm === 'beach') {
        // pond -> beach: pondBeachEntryTileSet (XE) — tile no pond que leva à beach
        return fromSet(XE);
      }
      if (targetRealm === 'ember') {
        // beach -> ember: beachEmberEntryTileSet (Ej)
        return fromSet(Ej);
      }
      if (targetRealm === 'frostmere') {
        // eldergrove -> frostmere: Yk (eldergroveFrostmereEntryTileSet)
        return fromSet(Yk);
      }
    } catch(e) {
      console.warn('[AutoGather] agNavGetPortalTile erro:', e.message);
    }
    return null;
  }

  function agNavDebug() {
    console.group('[AutoGather] Portal debug');
    try { console.log('h6 (pond portal):', h6 ? [...h6].slice(0,3) : 'undefined'); } catch(e) { console.log('h6 erro:', e.message); }
    try { console.log('w6 (eldergrove portal):', w6 ? [...w6].slice(0,3) : 'undefined'); } catch(e) { console.log('w6 erro:', e.message); }
    try { console.log('VE (wild portal):', VE ? [...VE].slice(0,3) : 'undefined'); } catch(e) { console.log('VE erro:', e.message); }
    try { console.log('NS (eldr portal cols):', NS, 'zk (row):', zk); } catch(e) { console.log('eldergrove cols/row erro:', e.message); }
    try { console.log('Ag (wild mid):', Ag, '$w (row):', $w); } catch(e) { console.log('wild mid/row erro:', e.message); }
    try { console.log('E:', ce, 'de:', de, 'gameState:', h); } catch(e) {}
    console.groupEnd();
  }
  window.__agNavDebug = agNavDebug;

  // Retorna o tile de saída (retorno ao world) do realm atual
  function agNavGetExitTile(fromRealm) {
    try {
      if (fromRealm === 'shack') {
        // Exit tiles do shack: [2,3], [0,4], [3,0], [3,1]
        // Usar [2,3] -- mais acessível (adjacente ao spawn [2,2])
        return { col: 2, row: 3 };
      }
      if (fromRealm === 'pond') {
        if (typeof g6 !== 'undefined' && g6.size > 0) {
          for (const k of g6) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'eldergrove') {
        if (typeof PS !== 'undefined' && PS.size > 0) {
          for (const k of PS) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
        if (typeof rie !== 'undefined') {
          const col = Array.isArray(rie) ? rie[0] : rie;
          return { col, row: Aj };
        }
      }
      if (fromRealm === 'wild' || fromRealm === 'wild_ext' || fromRealm === 'wild_exp') {
        if (typeof VE !== 'undefined' && VE.size > 0) {
          for (const k of VE) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'beach') {
        // beachReturnSet (AE) = tiles da beach que levam de volta ao pond
        if (typeof AE !== 'undefined' && AE.size > 0) {
          for (const k of AE) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'frostmere') {
        if (typeof Tg !== 'undefined' && Tg.size > 0) {
          for (const k of Tg) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'ember') {
        if (typeof z3 !== 'undefined' && z3.size > 0) {
          for (const k of z3) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
    } catch(e) {}
    return null;
  }

  function agNavTick() {
    if (!agNavTarget) return;

    // Já chegou no destino
    if (h===agNavTarget) {
      agNavTarget = null;
      clearTimeout(agNavTimer);
      agNavSetStatus('');
      if (agActive && agMode === 'fish') {
        agSetStatus('🎣 No mapa certo! Iniciando pesca…');
      }
      return;
    }

    // Se destino é o realm atual mas via world — já está no destino
    if (h==='world' && agNavTarget === 'world') {
      agNavTarget = null; agNavSetStatus(''); return;
    }

    // Rotas diretas de um realm intermediário (sem passar pelo world)
    // eldergrove → frostmere (portal dentro do eldergrove)
    if (h === 'eldergrove' && agNavTarget === 'frostmere') {
      const portal = agNavGetPortalTile('frostmere');
      if (portal) {
        if (ce === portal.col && de === portal.row) {
          agNavSetStatus('🌀 Entrando em Frostmere…');
          agNavTimer = setTimeout(agNavTick, 500); return;
        }
        const distP = Math.abs(ce - portal.col) + Math.abs(de - portal.row);
        if (distP <= 1) {
          agNavSetStatus('🌀 Entrando em Frostmere…');
          agNavTimer = setTimeout(agNavTick, 500); return;
        }
        const pp = r(ce, de, portal.col, portal.row);
        if (pp && pp.length) { qe = pp; if (!$e) Ll(); }
        agNavSetStatus('🚶 Indo para Frostmere (via Eldergrove)…');
        agNavTimer = setTimeout(agNavTick, 500); return;
      }
    }
    // pond → beach (portal dentro do pond)
    if (h === 'pond' && (agNavTarget === 'beach' || agNavTarget === 'ember')) {
      const portal = agNavGetPortalTile('beach');
      if (portal) {
        if (ce === portal.col && de === portal.row) {
          agNavSetStatus('🌀 Entrando na Beach…');
          agNavTimer = setTimeout(agNavTick, 500); return;
        }
        const pp = r(ce, de, portal.col, portal.row);
        if (pp && pp.length) { qe = pp; if (!$e) Ll(); }
        agNavSetStatus('🚶 Indo para Beach…');
        agNavTimer = setTimeout(agNavTick, 500); return;
      }
    }

    // Se não está no world, precisa sair primeiro pelo portal de retorno
    if (h!=='world') {
      const exit = agNavGetExitTile(h);
      if (!exit) {
        agNavSetStatus('⚠️ Sem saída conhecida de ' + (AG_REALM_LABELS[h] || h));
        agNavTimer = setTimeout(agNavTick, 2000);
        return;
      }
      // Já está no tile de saída — aguarda transição
      if (ce === exit.col && de === exit.row) {
        agNavSetStatus('🌀 Saindo de ' + (AG_REALM_LABELS[h] || h) + '…');
        agNavTimer = setTimeout(agNavTick, 500);
        return;
      }
      // Caminha até o tile de saída
      const distToExit = Math.abs(ce - exit.col) + Math.abs(de - exit.row);
      if (distToExit <= 1) {
        agNavSetStatus('🌀 Saindo de ' + (AG_REALM_LABELS[h] || h) + '…');
        agNavTimer = setTimeout(agNavTick, 500);
        return;
      }
      const path = r(ce, de, exit.col, exit.row);
      if (!path || !path.length) {
        agNavSetStatus('❌ Sem caminho para saída de ' + (AG_REALM_LABELS[h] || h));
        agNavTimer = setTimeout(agNavTick, 2000);
        return;
      }
      qe = path;
      if (!$e) Ll();
      agNavSetStatus('🚶 Saindo de ' + (AG_REALM_LABELS[h] || h) + ' → ' + (AG_REALM_LABELS[agNavTarget] || agNavTarget) + '…');
      agNavTimer = setTimeout(agNavTick, 500);
      return;
    }

    // Está no world — multi-hop para destinos não acessíveis diretamente
    var _effectiveTarget = agNavTarget;
    if (agNavTarget === 'beach' || agNavTarget === 'ember') {
      _effectiveTarget = 'pond'; // pond primeiro
    }
    if (agNavTarget === 'frostmere') {
      _effectiveTarget = 'eldergrove'; // eldergrove primeiro, depois frostmere
    }

    // Está no world — vai para o portal do destino
    const portal = agNavGetPortalTile(_effectiveTarget);
    if (!portal) {
      agNavSetStatus('❌ Portal não encontrado — veja console (F12)');
      console.warn('[AutoGather] Portal não encontrado para:', agNavTarget);
      agNavDebug();
      agNavTarget = null; return;
    }

    // Pond->beach multi-hop: se destino é ember e estamos no pond, ir para beach
    if (h==='pond' && agNavTarget === 'ember') {
      _effectiveTarget = 'beach';
      const beachPortal = agNavGetPortalTile('beach');
      if (beachPortal) {
        if (ce === beachPortal.col && de === beachPortal.row) {
          agNavSetStatus('🌀 Entrando na Beach…');
          agNavTimer = setTimeout(agNavTick, 500); return;
        }
        const bp = r(ce, de, beachPortal.col, beachPortal.row);
        if (bp && bp.length) { qe = bp; if (!$e) Ll(); }
        agNavSetStatus('🚶 Indo para Beach (caminho para Ember)…');
        agNavTimer = setTimeout(agNavTick, 500); return;
      }
    }

    // Verifica se já está no tile do portal (transição automática)
    if (ce === portal.col && de === portal.row) {
      agNavSetStatus('🌀 Entrando em ' + (AG_REALM_LABELS[agNavTarget] || agNavTarget) + '…');
      agNavTimer = setTimeout(agNavTick, 500);
      return;
    }

    // Caminha até o portal
    const path = r(ce, de, portal.col, portal.row);
    if (!path || !path.length) {
      agNavSetStatus('❌ Sem caminho para o portal');
      agNavTarget = null; return;
    }
    qe = path;
    if (!$e) Ll();
    agNavSetStatus('🚶 Indo para ' + (AG_REALM_LABELS[agNavTarget] || agNavTarget) + '…');
    agNavTimer = setTimeout(agNavTick, 500);
  }

  function agNavTo(realm) {
    if (h === realm) {
      agNavSetStatus('✓ Já estás em ' + (AG_REALM_LABELS[realm] || realm));
      return;
    }
    agNavTarget = realm;
    clearTimeout(agNavTimer);
    agNavTick();
  }

  function agNavCancel() {
    agNavTarget = null;
    clearTimeout(agNavTimer);
    agNavSetStatus('');
  }

  // Atualiza o display do mapa atual no painel
  function agUpdateRealmDisplay() {
    const host = document.getElementById('ag-panel-host');
    const el = host?.shadowRoot?.getElementById('ag-realm');
    if (!el) return;
    const label = AG_REALM_LABELS[h] || h;
    const iconSrc = AG_REALM_ICONS[h];
    const iconHtml = iconSrc ? '<img src="' + iconSrc + '" width="13" height="13" style="vertical-align:middle;margin-right:4px;image-rendering:pixelated" draggable="false">' : '';
    // Indica se o mapa atual suporta a feature ativa
    let indicator = '';
    if (agMode === 'fish') {
      indicator = AG_FISHING_REALMS.has(h)
        ? ' <span style="color:#3d9">✓ pesca OK</span>'
        : ' <span style="color:#e05">✗ sem pesca</span>';
    } else if (agMode === 'tree' || agIsRockMode()) {
      const ok = (function(){try{return JY();}catch(_){return false;}})();
      indicator = ok
        ? ' <span style="color:#3d9">✓ coleta OK</span>'
        : ' <span style="color:#e05">✗ sem coleta</span>';
    }
    el.innerHTML = `${label}${indicator}`;
  }

