    // ── DONATE ───────────────────────────────────────────────────────────────
    var DONATE_KEY   = 'kintara_ag_merch_donate';
    var DONATE_ITEMS = [
      { type: 'wood',             label: 'Wood'        },
      { type: 'stone',            label: 'Stone'       },
      { type: 'coal',             label: 'Coal'        },
      { type: 'cooked_fish_meat', label: 'Cooked Fish' },
      { type: 'metal',            label: 'Metal'       },
    ];

    function loadDonateConfig() {
      try { return JSON.parse(localStorage.getItem(DONATE_KEY) || '{}'); } catch(_) { return {}; }
    }
    function saveDonateConfig(cfg) {
      try { localStorage.setItem(DONATE_KEY, JSON.stringify(cfg)); } catch(_) {}
    }

    function getDonatedThisCycle(type) {
      var cfg = loadDonateConfig();
      var cycleId = _cycleData ? _cycleData.cycleId : null;
      if (!cycleId) return 0;
      return (cfg[cycleId] && cfg[cycleId][type]) || 0;
    }
    function markDonated(type, qty) {
      var cfg = loadDonateConfig();
      var cycleId = _cycleData ? _cycleData.cycleId : 0;
      if (!cfg[cycleId]) cfg[cycleId] = {};
      cfg[cycleId][type] = (cfg[cycleId][type] || 0) + qty;
      // Manter só últimos 3 ciclos
      var keys = Object.keys(cfg).map(Number).sort((a,b) => b-a);
      keys.slice(3).forEach(function(k) { delete cfg[k]; });
      saveDonateConfig(cfg);
    }

    function renderDonateSummary() {
      var el = $m('mc-donate-summary');
      if (!el) return;
      var DONATE_KEY = 'kintara_ag_merch_donate';
      var DONATE_ITEMS_LIST = ['wood','stone','coal','cooked_fish_meat','metal'];
      try {
        var cfg = JSON.parse(localStorage.getItem(DONATE_KEY) || '{}');
        var cycleId = _cycleData ? _cycleData.cycleId : null;
        if (!cycleId) { el.textContent = ''; return; }
        var parts = [];
        DONATE_ITEMS_LIST.forEach(function(type) {
          var target  = (cfg[cycleId] && cfg[cycleId]['target_' + type]) || 0;
          var donated = (cfg[cycleId] && cfg[cycleId][type]) || 0;
          if (target > 0 || donated > 0) {
            var color = donated >= target && target > 0 ? '#6ee7a0' : '#94a3b8';
            parts.push('<span style="color:' + color + '">' + type.replace('cooked_fish_meat','fish🍳') + ': ' + donated + '/' + target + '</span>');
          }
        });
        el.innerHTML = parts.length ? '🎁 ' + parts.join(' · ') : '';
      } catch(_) { el.textContent = ''; }
    }


    // Drag
