  try { Object.defineProperty(window, 'agClearBans', { value: agClearBans, writable: true, configurable: true }); } catch(_) { window.agClearBans = agClearBans; }
  try { globalThis.agBans = agBans; globalThis.agClearBans = agClearBans; } catch(_) {}
  console.info('[AutoGather] Tiles banidos: agBans() para listar | agClearBans() para limpar');
